commit c15ccfb24afa67d3c3f54e52cc1d1afa564715ed
Author: Nikita Popov <npopov@redhat.com>
Date:   Mon Aug 14 17:39:48 2023 +0200

    [InstCombine] Fix select + cast fold with constant expression (PR64669)

    The zext constant expression was detected by the fold, but then
    handled as a sext. Use ZExtOperator instead of ZExtInst to handle
    constant expressions.

    Fixes https://github.com/llvm/llvm-project/issues/64669.

diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index 01ca0894ac35..2722160e72c1 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -908,7 +908,7 @@ InstCombinerImpl::foldBinOpOfSelectAndCastOfSelectCondition(BinaryOperator &I) {

   auto NewFoldedConst = [&](bool IsTrueArm, Value *V) {
     bool IsCastOpRHS = (CastOp == RHS);
-    bool IsZExt = isa<ZExtInst>(CastOp);
+    bool IsZExt = isa<ZExtOperator>(CastOp);
     Constant *C;

     if (IsTrueArm) {

issue.body:
This is a recent regression. Clang at -O1 and above produced the wrong code.

Bisected to f12a5561b2cbfae384c9a31293938ee2acea79fd, which was committed by @antoniofrighetto 

Compiler explorer: https://godbolt.org/z/q4fsW5Ge7

```console
% cat a.c 
int printf(const char *, ...);
long a, e;
int b[72];
int c, g, h;
char d;
int main() {
  int *f = &b[25], *i = &c;
  d = f != i;
  e = a * d;
  *f = e + d;
  printf("%d\n", b[25]);
}
%
% clang-f12a556 -O0 a.c && ./a.out
1
% clang-f12a556 -O1 a.c && ./a.out
-1
% clang-f12a556 -O2 a.c && ./a.out
-1
%
```
